import React, { useState, useEffect } from 'react';
import { MoreVertical, Check, X, Filter, Download, Search, Eye, MessageSquare } from 'lucide-react';
import ApprovalModal from './ApprovalModal';

const StatusBadge = ({ status }) => {
  const styles = {
    'Approved': 'bg-green-500/10 text-green-500 border-green-500/20',
    'Pending': 'bg-yellow-500/10 text-yellow-500 border-yellow-500/20',
    'Rejected': 'bg-mas-red/10 text-mas-red border-mas-red/20',
    'Checked In': 'bg-blue-500/10 text-blue-500 border-blue-500/20',
    'Checked Out': 'bg-mas-text-dim/10 text-mas-text-dim border-mas-text-dim/20',
  };

  return (
    <span className={`px-2 py-1 text-[10px] font-bold uppercase tracking-wider border ${styles[status] || styles['Pending']}`}>
      {status}
    </span>
  );
};

const VisitorTable = ({ onViewDetails }) => {
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedVisitor, setSelectedVisitor] = useState(null);
  const [modalType, setModalType] = useState('Approve');
  const [isModalOpen, setIsModalOpen] = useState(false);

  const [visitorList, setVisitorList] = useState([
